var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"마지막까지 그 정도의 힘을 아껴두고 허를 찌르다니. 제법 머리를 썼구나.","JPN":"最後までこれほどの力を温存し隙を狙うとは、随分知恵を絞ったようだな。","ENG":"To think you conserved that much strength until the very end just to catch me off guard. Clever.","TWN":"在最後一刻，你竟然還能隱藏力量，偷襲我。你還挺有心計。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"허나 바라밀 명도조차 꺾지 못한 본좌를 한낱 이 몸의 작은 조각이 무슨 수로 꺾을까.","JPN":"だが、波羅蜜命刀ですら倒れなかった吾輩を、欠片ごときが如何にして倒すというのだ。","ENG":"But what could a mere fragment like you possibly do to defeat me, when even the Sword of Paramita failed?","TWN":"但連波羅密命刀都無法擊敗的本座，你這個區區身體的一小部分，能用什麼來擊敗？"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"본좌는 이제 이 기워 붙인 껍데기 따윈 벗어던지고 새로운 마왕의 육신을 얻으리라.","JPN":"吾輩はこの継ぎ接ぎの皮を脱ぎ捨て、新たな魔王の肉体を手に入れよう。","ENG":"Now I shall cast off this stitched-together shell and claim my true form as Demon Lord.","TWN":"本座現在要拋棄這具縫補的外殼，獲得新的魔王之身。"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_1","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그전에 마지막으로… 본좌의 작은 조각인 너를 삼켜, 다시 거두어주마.","JPN":"その前に、今ここで……吾輩の小さな欠片であるお前を呑み込み、回収してやろう。","ENG":"But before that… I'll devour you, fragment of mine, and reclaim you fully.","TWN":"在這之前，最後… 本座將吞噬你，這個本座的一小部分，再次收回。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"이 뱃속에서 네 여인과 그 못 다한 연을 매듭짓거라.","JPN":"吾輩の腹の底で、お前の女と果たせなかった想いを遂げるといい。","ENG":"Settle what remains of your pitiful bond with your woman inside this belly.","TWN":"就在我的肚子裡，與你的女人，為那未了的緣分畫下句點吧。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허억…!","JPN":"はあっ……！","ENG":"*Gasp…!*","TWN":"啊…！"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"깜짝이야.","JPN":"びっくりした。","ENG":"Whoa.","TWN":"嚇我一跳。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"왜 그렇게 식은 땀을 흘려? 악몽이라도 꾼 거야?","JPN":"どうしたの？　そんなに冷や汗かいて……悪夢でも見た？","ENG":"Why are you covered in cold sweat? Had a nightmare?","TWN":"你為什麼流這麼多冷汗？做惡夢了嗎？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화…?","JPN":"レンカ……？","ENG":"Yeonhwa…?","TWN":"蓮華…？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…뭐야. 그 죽은 사람 쳐다보는 듯한 눈빛은.","JPN":"……何よ、お化けでも見たような顔して。","ENG":"…What's with that look? Like you've seen a ghost.","TWN":"…什麼啊。你那是什麼看著死人的眼神。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"밥 차렸으니까 얼른 일어나서 먹기나 해.","JPN":"ご飯できたから、早く起きなさい。","ENG":"Food is ready. Come eat already.","TWN":"飯做好了，快起來吃飯。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건? 계란찜?","JPN":"これは？　茶碗蒸し？","ENG":"This is… steamed egg?","TWN":"這是？蒸蛋？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"왜? 당신이 제일 좋아하잖아. 아니야?","JPN":"何？　あなたの好物でしょう？　違った？","ENG":"What? It's your favorite, isn't it?","TWN":"怎麼了？你不是最喜歡嗎？不對嗎？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…싫어하는 건 아닐세. 다만…","JPN":"……そうではない。ただ……","ENG":"…I don't dislike it. It's just that…","TWN":"…不是不喜歡。只是…"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 나를 위해 요리를 해주는 것이 흔한 일은 아니니까.","JPN":"そなたが某に料理を作ってくれるのは、そうそうあることではないゆえ。","ENG":"You cooking for me isn't exactly common.","TWN":"你為我做飯這種事，並不常見。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"별 수 없잖아. 당신은 늦잠을 자고, 난 배가 고픈데, 내 끼니만 챙길 순 없으니까.","JPN":"仕方ないじゃない。お腹空いたのにあなたはまだ寝てるし、自分だけ食べるわけにはいかないもの。","ENG":"What choice did I have? You overslept, and I was hungry. And I couldn't make just mine.","TWN":"沒辦法啊。你睡懶覺，我又肚子餓，我不能只顧自己啊。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"맛은 어때? 간은 괜찮아?","JPN":"味はどう？　塩加減は？","ENG":"So, how is it? Did I season it right?","TWN":"好吃嗎？味道還行嗎？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…조금 싱겁군.","JPN":"……少し薄いな。","ENG":"…A little bland.","TWN":"…有點淡。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"흥, 다신 안 만들어줄래.","JPN":"ふん、二度と作ってやらないんだから。","ENG":"Hmph, fine. I won't make it again.","TWN":"哼，我再也不給你做了。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래도 좋다네. 그대가 차려주는 따뜻한 밥상을 싫어할 남자가 있겠나.","JPN":"それでも美味い。そなたが作ってくれる料理を拒む男などいるものか。","ENG":"It's still good. What man could dislike a warm meal made by you?","TWN":"這樣也很好。有哪個男人會不喜歡你做的熱騰騰飯菜呢。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…뭐야. 이제 와서 그런 말 한다고 봐줄 줄 알고?","JPN":"……何よ、今更おだてても遅いからね。","ENG":"…Huh? You think sweet-talking me now will get you off the hook?","TWN":"…什麼啊。你以為現在說這種話，我就會原諒你嗎？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내일부턴 일찍 일어나겠다고 약속하지. 그땐 아침밥도 함께 준비하고. ","JPN":"明日からは早起きすると約束しよう。朝飯も一緒に作ろう。","ENG":"I promise I'll wake up early from now on. We'll make breakfast together next time.","TWN":"我保證明天會早點起床。到時候我們一起做早飯。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"빨리 내일 아침이 왔으면 좋겠네.","JPN":"早く明日の朝が来るといいわ。","ENG":"Can't wait for tomorrow morning.","TWN":"真希望明天早上快點到來。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…연화.","JPN":"……レンカ。","ENG":"…Yeonhwa.","TWN":"…蓮華。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지금 우는 거요?","JPN":"泣いているのか？","ENG":"Are you crying?","TWN":"你在哭嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러게… 왜 갑자기 주책 맞게 눈물이 나오는 거람?","JPN":"本当……私ったら、どうして急に涙が出るのかしら。","ENG":"Guess I am… Why am I tearing up all of a sudden?","TWN":"是啊… 我怎麼突然這麼沒出息地哭了呢？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지금 이 순간이 행복하고 소중해서 그런가 봐.","JPN":"今この瞬間が幸せで、大切だからかもね。","ENG":"I think it's because this moment feels so happy. So precious.","TWN":"可能是因為現在這個瞬間，太幸福，太珍貴了。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나도 마찬가지요.","JPN":"某もだ。","ENG":"I feel the same.","TWN":"我也一樣。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"얼마나?","JPN":"どれぐらい？","ENG":"How much?","TWN":"有多幸福？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이것이 꿈이라면… 깨어나지 않아도 좋을 정도로 행복하다네.","JPN":"これが夢なら……覚めなくていいと思うほど、幸せだ。","ENG":"If this is a dream… then I'd rather never wake.","TWN":"如果這是個夢… 我希望永遠不要醒來。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"여기로 와본 건 정말 오랜만이네.","JPN":"久しぶりだわ、ここに来るの。","ENG":"It's been so long since I last came here.","TWN":"來到這裡，真是好久不見了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 숲은…?","JPN":"この森は……？","ENG":"This forest…","TWN":"這片森林是…？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내가 스승님과 함께 수행을 하던 곳.","JPN":"私が師匠と修行してた森よ。","ENG":"It's where I used to train with my master.","TWN":"我和師父一起修行的地點。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그땐 정말 많이 혼났지. 엄하고 무정한 스승님 때문에 힘들었는데, 막상 돌이켜 보면…","JPN":"あの頃は本当にたくさん怒られたものね。厳しくて薄情な師匠のせいで大変だったけど、今振り返ってみると……","ENG":"I got scolded so much back then. Harsh, cold, and strict… it was tough. But looking back now…","TWN":"那時候真的被罵得很慘。嚴格又無情的師父，讓我很辛苦，但回過頭來看…"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…으음, 아니야. 지나고 나서도 딱히 그 시절이 그립진 않네.","JPN":"……ううん、違うわ。やっぱりあの頃は恋しくない。","ENG":"…Mm, no, not really. I don't feel nostalgic for those days.","TWN":"…嗯，不對。即使回過頭看，我也不懷念那段時光。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 몸서리칠 정도면 정말 엄한 스승이었나 보군.","JPN":"そなたがそこまで身震いするほどなら、よほど厳しい師匠だったのだろうな。","ENG":"If it made you shudder that much, your master must've been quite the taskmaster.","TWN":"能讓你厭惡到這種地步，看來你師父真的很嚴厲。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"결국, 명달 대장 혼자서 범을 막아낸 덕에 내 솜씨는 필요없어졌지만 말이야.","JPN":"結局、アカタツ隊長が一人で虎を倒したから、私の出番はなかったけどね。","ENG":"In the end, it didn't matter. Commander Myeongdal handled the Tiger alone. My skills weren't needed after all.","TWN":"最終，多虧了明達隊長一個人阻止了老虎，所以我的本事也用不上了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장이… 범을 이겼다고?","JPN":"アカタツ隊長が……虎を倒した？","ENG":"Commander Myeongdal… defeated the Tiger?","TWN":"明達隊長… 戰勝了老虎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"오늘따라 이상하네. 정말 기억이 안 나는 거야?","JPN":"あなた、今日ちょっとおかしいわ。本当に思い出せないの？","ENG":"You're acting strange today. Don't tell me you've really forgotten?","TWN":"你今天怎麼這麼奇怪。真的不記得了嗎？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"아니… 이상한 꿈을 꿔서 잠시 헷갈린 모양일세.","JPN":"いや……変な夢を見たせいで、混乱したようだ。","ENG":"No… I must've been thrown off by a strange dream.","TWN":"不是… 我做了一個奇怪的夢，所以有些混亂。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그래. 떠올랐어.","JPN":"……ああ、思い出した。","ENG":"…Yes. It's coming back now.","TWN":"…對了。我想起來了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장은… 삼군문 모두를 대신해 범과의 결전에서 홀로 희생하셨지.","JPN":"アカタツ隊長は……三軍門の皆の代わりに、虎との決戦で一人犠牲になったのだったな。","ENG":"Commander Myeongdal… sacrificed himself in the final battle against the Tiger, on behalf of all of Trivanguard.","TWN":"明達隊長… 代替所有三軍門的人，在與老虎的決戰中獨自犧牲了。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"간만에 인사드리러 갈까?","JPN":"久しぶりに、お墓参りに行きましょうか。","ENG":"Want to go pay our respects?","TWN":"要不要久違地去問候他？"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"여기서 그리 멀지도 않잖아.","JPN":"ここからそんなに遠くないもの。","ENG":"It's not far from here.","TWN":"離這裡也不遠。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"잠깐 못 뵌 사이에 잡초가 많이 자랐네.","JPN":"しばらく来ない間に雑草がたくさん生えたわね。","ENG":"The weeds have grown a lot since we last visited.","TWN":"好一陣子沒見，雜草長得真多。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"세상을 구하신 분의 묘지라기엔 조금 조촐한 듯하군.","JPN":"世界を救った方の墓にしては、やや質素すぎるな。","ENG":"A modest grave for someone who saved the world.","TWN":"作為拯救世界之人的墳墓，似乎有點寒酸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"마음 같아선 왕릉을 세워도 부족하겠지만, 관리국은 뭐든 비밀스러워야하잖아.","JPN":"王様並みのお墓にしたい気持ちは山々だけど、管理局は何でも秘密にしたがるじゃない。","ENG":"Even a royal tomb wouldn't be enough. But the Administration keeps everything under wraps.","TWN":"如果可以，我希望能為他建一座王陵，但管理局的一切都必須保密。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래도 당신 말이 맞네. 이런 조촐한 곳에 모셔두는 건 예우가 아니지.","JPN":"でも、あなたの言う通りよ。こんなに狭い所に置いておくのは失礼よね。","ENG":"Still, you're right. Leaving him in a place like this isn't enough. He deserves better.","TWN":"不過你說的對。把你安葬在這麼簡陋的地方，確實不夠禮遇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앞으로 우리가 좀 더 자주 와드려야겠다.","JPN":"これからはもっとたくさん来るようにしましょう。","ENG":"We'll just have to visit more often ourselves.","TWN":"以後我們要更常來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여긴… 한때 삼군문이 연무장으로 쓰던 곳이었지.","JPN":"ここは……かつて三軍門の訓練場だった場所だな。","ENG":"This was… once the Trivanguard's training grounds.","TWN":"這裡… 曾經是三軍門的練武場。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래서 추억이 많잖아.","JPN":"思い出もたくさんあるわ。","ENG":"Lots of memories here.","TWN":"所以有很多回憶。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"대부분은 혼나는 거였지만.","JPN":"ほとんどは怒られた記憶だけど。","ENG":"Mostly of us getting scolded, though.","TWN":"雖然大部分都是被罵的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이곳도 그새 변했군. 이렇게 나무가 많이 자라던 곳은 아니었는데.","JPN":"ここもすっかり変わり果ててしまったな。こんなに木が多い場所ではなかったが。","ENG":"This place has changed. It never had this many trees.","TWN":"這個地方也變了。以前這裡可沒有這麼多樹。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그러게. 못 보던 나무들이야..","JPN":"そうね。見慣れない木……","ENG":"Yeah. Some of these trees weren't here before…","TWN":"是啊。這些樹以前沒見過。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"돌아갈까? 나 배고파.","JPN":"帰りましょうか？　お腹空いたわ。","ENG":"Should we head back? I'm hungry.","TWN":"回去吧？我肚子餓了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"그래. 명달 대장은 죽었어.","JPN":"そうだ、アカタツ隊長は死んだ。","ENG":"Right. Commander Myeongdal is gone.","TWN":"好。明達隊長死了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"그 대가로 세상은 범으로부터의 화를 면했고, 우리 두 사람은 평온한 삶을 누리게 되었지.","JPN":"その代償として世界は虎の災害を免れ、我ら2人は平穏な日々を手に入れた。","ENG":"In exchange, the world was spared from the Tiger's wrath. The two of us were granted peace.","TWN":"作為代價，世界免於老虎的災禍，我們兩個人過上了平靜的生活。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"분명… 그것으로 족할 터인데…","JPN":"きっと……それで十分なはずなのに……","ENG":"Surely… that should be enough, and yet…","TWN":"這應該… 就足夠了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"저 나무들이 키가 큰 것이 못내 마음에 걸리는 건, 어째서일까.","JPN":"そびえ立つ木々の高さが気にかかるのは、なぜだろう。","ENG":"Why do those towering trees leave me so unsettled?","TWN":"但這些樹長得這麼高，讓我心裡有些不安，這是為什麼呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이젠 찌개도 잘 끓이는 거야? 당신도 요리 실력이 제법 늘었네.","JPN":"もう鍋も作れるの？　あなた、料理の腕がだいぶ上がったわね。","ENG":"So you're even good at stew now? Your cooking's gotten a lot better.","TWN":"你現在連鍋燒也做得這麼好了？你的廚藝進步不少呢。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대 실력에 비할 바는 아니지만, 생쥐도 부뚜막 삼년이면 요리를 가르친다잖소.","JPN":"そなたの腕には及ばないが、ネズミも台所に3年いれば料理を教えられるというではないか。","ENG":"It's nothing compared to yours, but even a mouse learns to cook after three years by the stove.","TWN":"沒辦法和你的手藝相比，但俗話說，老鼠在灶台上待三年也會學會做飯。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그것도 옛날 속담이야?","JPN":"それって昔のことわざ？","ENG":"Some old proverb?","TWN":"這是古時候的諺語嗎？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"만화영화 내용일세.","JPN":"アニメ映画の話だ。","ENG":"Cartoon, actually.","TWN":"是漫畫裡的。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앗, 어렸을 때 본 거 같아. 그거 아마도 제목이…","JPN":"あ、子どもの頃に見たかも。確か、タイトルは……","ENG":"Oh, I think I watched that when I was little. The title was…","TWN":"啊，我小時候好像看過。那個標題應該是…"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"연화.","JPN":"レンカ。","ENG":"Yeonhwa.","TWN":"蓮華。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"곶감.","JPN":"干し柿。","ENG":"The dried persimmons.","TWN":"柿餅。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"하나도 먹지 않았군.","JPN":"まったく食べていなかった。","ENG":"You didn't touch a single one.","TWN":"你一個都沒吃。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이상해? 당신도 알잖아.","JPN":"え？　知ってるでしょう。","ENG":"Is that strange? You know too.","TWN":"很奇怪嗎？你也知道。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"나… 곶감 별로 안 좋아하는 거.","JPN":"私……干し柿はあまり好きじゃないの。","ENG":"I… never really liked dried persimmons.","TWN":"我… 不太喜歡柿餅。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그랬었지. 내 실수요.","JPN":"……そうだったな。すまない。","ENG":"…Right. My mistake.","TWN":"…是啊。是我的失誤。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"설거지는 내가 할게. 당신은 밤 산책이라도 다녀오는 게 어때?","JPN":"皿洗いは私がやるわ。あなたは散歩でも行って来たら？","ENG":"I'll handle the dishes. Why don't you go for a night stroll?","TWN":"碗我來洗。你出去散散步怎麼樣？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"산책…?","JPN":"散歩……？","ENG":"A stroll…?","TWN":"散步…？"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"오늘 밤은 보름달이 밝잖아. 불빛은 필요 없을 거야.","JPN":"今日は満月でしょう。明かりはいらないはずよ。","ENG":"There's a full moon tonight. You won't need a lantern.","TWN":"今晚月亮很圓很亮。應該不需要燈。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"뜻 모를 위화감을 뒤로 한 채 밖으로 나선 나는 하늘을 보았네.","JPN":"なんとも言えぬ違和感を感じつつ、外に出た某は空を見上げた。","ENG":"Leaving behind a sense of vague unease, I stepped outside and looked to the sky.","TWN":"我將那股難以言喻的違和感拋諸腦後，走到外面，看著天空。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"하늘은 밝았지만, 이상하게도 그녀가 말한 보름달은 보이지 않았어.","JPN":"確かに夜空は明るかったが、不思議なことに満月は見当たらなかった。","ENG":"The sky was bright, but the full moon was nowhere to be seen.","TWN":"天空很亮，但奇怪的是，我卻看不到月亮。"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 정처없이 길을 걷다 다다른 곳은… 다름아닌 명달 대장의 묘비 앞이었지.","JPN":"あてもなく足を運ぶと……いつの間にアカタツ隊長の墓場に辿り着いていた。","ENG":"I walked, without direction, until I found myself… at Commander Myeongdal's grave.","TWN":"我漫無目的地走著，最後來到的地方… 竟然是明達隊長的墳墓。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…참으로 이상하지 않은가.","JPN":"……実におかしなことだ。","ENG":"…Isn't it strange?","TWN":"…這不是很奇怪嗎。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"분명 명달 대장의 무덤이 여기에 있는데…","JPN":"確かにアカタツ隊長の墓がここにあるのに……","ENG":"His grave is right here, and yet…","TWN":"明明明達隊長的墳墓就在這裡…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나는 명달 대장을 이 손으로 묻은 기억이 없소.","JPN":"某はアカタツ隊長をこの手で埋めた覚えがない。","ENG":"I have no memory of ever burying him.","TWN":"我卻不記得我用這雙手埋葬了他。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"마치, 돌아올 수 없는 인연이 내 곁으로 돌아온 것처럼.","JPN":"まるで、取り戻せない因縁が、某のもとへ戻ってきたように。","ENG":"As if a bond once lost forever has somehow found its way back to me.","TWN":"就好像，無法回頭的緣分回到了我身邊一樣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇다면…","JPN":"ならば……","ENG":"If that's the case…","TWN":"那麼…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 무덤 아래엔 대체 무엇이 있는 거지?","JPN":"この墓の下には何があるのだ？","ENG":"Then what truly lies beneath this grave?","TWN":"這個墳墓下面，到底是什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_05"},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"This is…","TWN":"這是…？"},"stage":{"bg":"SKY_BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우물에서 찾은 책 한 권을 기억하느냐?","JPN":"イドで見つけた手帳を覚えているか？","ENG":"Remember the notebook from the Well?","TWN":"你還記得在井裡找到的那本書嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"마지막 장을 살펴보아라. 전할 말을 남겨두었으니.","JPN":"最後のページを見るといい。伝言を残しておいた。","ENG":"Check the final page. There's a message for you.","TWN":"看看最後一頁。我留下了要說的話。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"명달 대장… 참으로 멀리까지 보셨구려.","JPN":"アカタツ隊長……遠くまで見据えていたものだ。","ENG":"Commander Myeongdal… You truly saw far ahead.","TWN":"明達隊長… 你看得真遠。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"찾아냈구나.","JPN":"見つけたのね。","ENG":"So you found it.","TWN":"你找到了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 난 당신을 보내지 않을 거야.","JPN":"でも私はあなたを行かせないわ。","ENG":"But I won't let you leave.","TWN":"但我不會讓你走的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 다리를 잘라내는 한이 있어도.","JPN":"その足を切り落としてでも。","ENG":"Even if I have to sever your legs to stop you.","TWN":"即使要斬斷你的雙腿。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…고맙소.","JPN":"……感謝する。","ENG":"…Thank you.","TWN":"…謝謝你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"속절없는 사람이 연못에 돌을 던지듯…","JPN":"無情な人間が池に投げる石ころのように……","ENG":"Like a helpless soul tossing stones into a pond…","TWN":"就像一個沒有指望的人，往池塘裡扔石頭…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"한 맺힌 창귀의 백 마디 말은 지금껏 내 정신을 어둡게 하였지.","JPN":"恨みを抱いた倀鬼が言い放つ百の真心は、今まで某の心を濁らせた。","ENG":"The hundred words flung by that vengeful ghost thrall once clouded my heart.","TWN":"懷有遺憾的倀鬼說的每一句話，至今都讓我的精神變得渾濁。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나, 오늘 그대가 들려준 한 마디 거짓말은 내 정신을 어느 때보다 밝게 해주었네.","JPN":"しかし、今日そなたが聞かせてくれた一言の嘘は、某の心をいつになく平穏にさせてくれた。","ENG":"But the single lie you told today brought me so much peace.","TWN":"但是，今天你說的一句謊話，讓我的精神比任何時候都更清醒。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아니. 아직 늦지 않았어.","JPN":"いいえ、まだ間に合うわ。","ENG":"No, it's not too late.","TWN":"不。還不晚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"부질없는 속세 따윈 잊고, 이곳에 남아 나와 평생을 함께 하자. 하담.","JPN":"無意味な現は忘れて、ここで私と生涯を添い遂げましょう、カタン。","ENG":"Forget the pointless world outside, and stay here with me. For the rest of our lives, Ha Dam.","TWN":"忘掉那些無用的世俗，留在這裡，和我一起度過一生吧。夏垣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그래.","JPN":"……そうだな。","ENG":"…Yes.","TWN":"…好。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"처음부터 늦은 적은 없었지.","JPN":"最初から遅れたことはなかった。","ENG":"From the very beginning, it was never too late.","TWN":"從來就沒有晚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리의 운명은 그저 흘러가며 때를 기다릴 뿐이니.","JPN":"我らの運命はただ流れ、時を待つのみ。","ENG":"Our fate simply flows onward, waiting for the right moment.","TWN":"我們的命運，只是在流動中等待時機。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS2"},"R":null}}}]`);export{e as default};